#include <iostream>
using namespace std;

class Node {
    public:
    int value;
    Node* next;

    // Constructor to initialize the node with a given value
    Node(int val): value(val), next(nullptr) {}
};

class LinkedList {
    public:
    Node* head;
    Node* tail;

    void insertAtEnd(int value) {
        Node* newNode = new Node(value);

        if (head == NULL) {
            head = newNode;
        } else {
            tail -> next = newNode;
        }

        // Set newNode as the tail 
        tail = newNode;

        // Set next of tail to head
        tail -> next = head;
    }

    int solveJosephus() {
        Node* current = head;

        // This condition will be true when there is only one element left in the list
        while (current -> next != current) {
            Node* knifePass = current -> next -> next;
            if (current -> next == head) {
                // We kill the current.next person, therefore if that is the head of the list, then the head needs to be updated to its next element
                head = knifePass;
            }

            // Killing the next person (Removing the pointer pointing to that node)
            current -> next = knifePass;

            // Passing the knife
            current = current -> next;
        }
        return current -> value;
    }

};

int main() {
    int t, n;
    cin >> t;

    while (t--) {
        cin >> n;

        LinkedList* list = new LinkedList();
        for (int i = 1; i <= n; i++) {
            list -> insertAtEnd(i);    
        }
        cout << list -> solveJosephus() << '\n'; 
    }
}

